  1	import {
  2	  Action,
  3	  ActionServiceProvider,
  4	  Alert,
  5	  AlertStates,
  6	  ResourceLink,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  alertSource,
 10	  AlertState,
 11	  AlertStateDescription,
 12	  isActionWithCallback,
 13	  isActionWithHref,
 14	  MonitoringResourceIcon,
 15	  NamespaceGroupVersionKind,
 16	  Severity,
 17	} from '../AlertUtils';
 18	import { AlertSource } from '../../../components/types';
 19	import { Td, Tr } from '@patternfly/react-table';
 20	import { DropdownItem, Flex, FlexItem } from '@patternfly/react-core';
 21	import KebabDropdown from '../../../components/kebab-dropdown';
 22	import React from 'react';
 23	import { useTranslation } from 'react-i18next';
 24	import { useHistory, useRouteMatch } from 'react-router';
 25	import { AlertResource, alertState } from '../../../components/utils';
 26	import {
 27	  getAlertUrl,
 28	  getNewSilenceAlertUrl,
 29	  usePerspective,
 30	} from '../../../components/hooks/usePerspective';
 31	import { Link } from 'react-router-dom';
 32	
 33	const tableAlertClasses = [
 34	  'pf-v6-u-w-50 pf-u-w-33-on-sm', // Name
 35	  'pf-m-hidden pf-m-visible-on-sm', // Severity
 36	  '', // Namespace
 37	  '', // State
 38	  'pf-m-hidden pf-m-visible-on-sm', // Source
 39	  'pf-m-hidden pf-m-visible-on-sm', // Cluster
 40	  'dropdown-kebab-pf pf-v6-c-table__action',
 41	];
 42	
 43	const AlertTableRow: React.FC<{ alert: Alert }> = ({ alert }) => {
 44	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 45	  const { perspective } = usePerspective();
 46	  const history = useHistory();
 47	  const match = useRouteMatch<{ ns: string }>();
 48	
 49	  const namespace = match.params.ns;
 50	
 51	  const state = alertState(alert);
 52	
 53	  const title: string = alert.annotations?.description || alert.annotations?.message;
 54	
 55	  const dropdownItems = [];
 56	
 57	  if (state !== AlertStates.Silenced) {
 58	    dropdownItems.unshift(
 59	      <DropdownItem
 60	        key="silence-alert"
 61	        onClick={() => history.push(getNewSilenceAlertUrl(perspective, alert, namespace))}
 62	      >
 63	        {t('Silence alert')}
 64	      </DropdownItem>,
 65	    );
 66	  }
 67	
 68	  const getDropdownItemsWithExtension = (actions: Action[]) => {
 69	    const extensionDropdownItems = [];
 70	    actions.forEach((action) => {
 71	      if (isActionWithHref(action)) {
 72	        extensionDropdownItems.push(
 73	          <DropdownItem key={action.id} href={action.cta.href}>
 74	            {action.label}
 75	          </DropdownItem>,
 76	        );
 77	      } else if (isActionWithCallback(action)) {
 78	        extensionDropdownItems.push(
 79	          <DropdownItem key={action.id} onClick={action.cta}>
 80	            {action.label}
 81	          </DropdownItem>,
 82	        );
 83	      }
 84	    });
 85	    return dropdownItems.concat(extensionDropdownItems);
 86	  };
 87	
 88	  return (
 89	    <Tr>
 90	      <Td className={tableAlertClasses[0]} title={title}>
 91	        <Flex spaceItems={{ default: 'spaceItemsNone' }} flexWrap={{ default: 'nowrap' }}>
 92	          <FlexItem>
 93	            <MonitoringResourceIcon resource={AlertResource} />
 94	          </FlexItem>
 95	          <FlexItem>
 96	            <Link
 97	              to={getAlertUrl(
 98	                perspective,
 99	                alert,
100	                alert?.rule?.id,
101	                alert?.labels?.namespace || namespace,
102	              )}
103	              data-test-id="alert-resource-link"
104	            >
105	              {alert?.labels?.alertname}
106	            </Link>
107	          </FlexItem>
108	        </Flex>
109	      </Td>
110	      <Td className={tableAlertClasses[1]} title={title}>
111	        <Severity severity={alert.labels?.severity} />
112	      </Td>
113	      <Td className={tableAlertClasses[2]} title={title}>
114	        {alert.labels?.namespace ? (
115	          <ResourceLink
116	            groupVersionKind={NamespaceGroupVersionKind}
117	            name={alert.labels?.namespace}
118	          />
119	        ) : (
120	          '-'
121	        )}
122	      </Td>
123	      <Td className={tableAlertClasses[3]} title={title}>
124	        <AlertState state={state} />
125	        <AlertStateDescription alert={alert} />
126	      </Td>
127	      <Td className={tableAlertClasses[4]} title={title}>
128	        {alertSource(alert) === AlertSource.User ? t('User') : t('Platform')}
129	      </Td>
130	      {perspective === 'acm' && (
131	        <Td className={tableAlertClasses[5]} title={title}>
132	          {alert.labels?.cluster}
133	        </Td>
134	      )}
135	      <Td className={tableAlertClasses[6]} title={title}>
136	        <ActionServiceProvider context={{ 'monitoring-alert-list-item': { alert: alert } }}>
137	          {({ actions, loaded }) => {
138	            if (loaded && actions.length > 0) {
139	              return <KebabDropdown dropdownItems={getDropdownItemsWithExtension(actions)} />;
140	            } else {
141	              return dropdownItems?.length > 0 ? (
142	                <KebabDropdown dropdownItems={dropdownItems} />
143	              ) : null;
144	            }
145	          }}
146	        </ActionServiceProvider>
147	      </Td>
148	    </Tr>
149	  );
150	};
151	
152	export default AlertTableRow;

