 1	import * as React from 'react';
 2	import { Dropdown, DropdownList, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 3	import EllipsisVIcon from '@patternfly/react-icons/dist/esm/icons/ellipsis-v-icon';
 4	
 5	import { useBoolean } from './hooks/useBoolean';
 6	
 7	const KebabDropdown: React.FC<{ dropdownItems: any[] }> = ({ dropdownItems }) => {
 8	  const [isOpen, setIsOpen, setOpen, setClosed] = useBoolean(false);
 9	
10	  return (
11	    <Dropdown
12	      isOpen={isOpen}
13	      onSelect={setClosed}
14	      onOpenChange={(open: boolean) => (open ? setOpen() : setClosed())}
15	      popperProps={{ position: 'right' }}
16	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
17	        <MenuToggle
18	          ref={toggleRef}
19	          aria-label="toggle menu"
20	          data-test-id="kebab-button"
21	          variant="plain"
22	          onClick={setIsOpen}
23	          isExpanded={isOpen}
24	        >
25	          <EllipsisVIcon />
26	        </MenuToggle>
27	      )}
28	      shouldFocusToggleOnSelect
29	    >
30	      <DropdownList>{dropdownItems}</DropdownList>
31	    </Dropdown>
32	  );
33	};
34	
35	export default KebabDropdown;

